251:         foreach (var id in stateIdSet)
252:         {
253:             if (successfulLogIdSet.Contains(id)) continue;
254:             if (!string.IsNullOrEmpty(pendingId)
255:                 && string.Equals(id, pendingId, StringComparison.Ordinal)
256:                 && stateIds.Count(s => string.Equals(s, id, StringComparison.Ordinal)) == 1
257:                 && !allLogIdSet.Contains(id))
258:             {
259:                 pendingApplied = true;
260:                 continue;
261:             }
262:             result.Failures.Add(F(id, "state-transition-not-logged",
263:                 $"id '{id}' is in appliedTransitions but has no successful log entry"));
264:         }
265:         return pendingApplied;
266:     }
